diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..3c0c3b91c2c4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -993,9 +993,41 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+
+  // Fold (add (zext nneg (add X, C1)), C2) -> (add (sext X), C1+C2).
+  // When X >= -C1 (guaranteed by nneg on zext), we have:
+  //   zext(add(X, C1)) + C2 = (X + C1) + C2 = X + C1 + C2
+  //   sext(X) + C1 + C2 = X + C1 + C2 (since X >= -C1 means X in valid range)
+  if (auto *ZExt = dyn_cast<ZExtInst>(Op0))
+    if (ZExt->hasNonNeg())
+      if (Value *ZExtSrc = ZExt->getOperand(0))
+        if (auto *InnerAdd = dyn_cast<BinaryOperator>(ZExtSrc))
+          if (InnerAdd->getOpcode() == Instruction::Add &&
+              InnerAdd->hasNoSignedWrap() &&
+              InnerAdd->hasOneUse()) {
+            Value *X = nullptr;
+            Constant *C1 = nullptr;
+            // Match add X, C1 or add C1, X
+            if (match(InnerAdd->getOperand(0), m_Constant(C1)) &&
+                match(InnerAdd->getOperand(1), m_Value(X))) {
+              // operands are C1, X
+            } else if (match(InnerAdd->getOperand(1), m_Constant(C1)) &&
+                       match(InnerAdd->getOperand(0), m_Value(X))) {
+              // operands are X, C1
+            } else {
+              C1 = nullptr;
+            }
+            if (C1) {
+              // Extend C1 to match Ty before adding to Op1C
+              Constant *C1Wide = ConstantFoldCastOperand(Instruction::SExt, C1, Ty, DL);
+              Constant *NewC = ConstantExpr::getAdd(C1Wide, Op1C);
+              Value *SExt = Builder.CreateSExt(X, Ty);
+              return BinaryOperator::CreateAdd(SExt, NewC);
+            }
+          }
+
   return nullptr;
 }
-
 // match variations of a^2 + 2*a*b + b^2
 //
 // to reuse the code between the FP and Int versions, the instruction OpCodes

